command.text:
        /* <flatten type="Javascript"> */
var f = this, g = f.grid, m = f.getItem('ma_nv2').value;
if (m.indexOf(g._employeeID) != -1) {
  $message.show(f._language == 'v' ? 'Dữ liệu không hợp lệ.' : 'Invalid Data.', String.format('$find(\'{0}\').focus(\'{1}\');', f.get_id(), 'ma_nv2'));
  f._checked = false;
}
/* </flatten> */

script.text:
      &OutlineEntry;
      /* <flatten type="Javascript"> */
function active$ShiftScheduleCopyRow(f) {
  f.add_onResponseComplete(on$ShiftScheduleCopyRow$ResponseComplete);
  init$ShiftScheduleCopyRow(f);
  changeLookupReadonly(f, 'ma_nv2', true);
}
function close$ShiftScheduleCopyRow(f) {f.remove_onResponseComplete(on$ShiftScheduleCopyRow$ResponseComplete);}
function init$ShiftScheduleCopyRow(f) {
  var g = f.grid;
  f.getItem('employeeID').value = g._employeeID;
  f.getItem('thang').value = g._month;
  f.getItem('nam').value = g._year;
  f.getItem('ma_bp').value = g._dept;
  f.getItem('ma_nv').value = g._staff;
  f.getItem('ma_vtr').value = g._pos;
  f.getItem('bac_ql').value = g._grade;
  f.getItem('bp_ref').value = g._deptRef;
}
function onChange$ShiftScheduleCopyRow$Department(o) {o.parentForm.request('Reference', 'Reference', ['ma_bp2']);}
function on$ShiftScheduleCopyRow$ResponseComplete(f, e) {
  var f = e.object, g = f.grid, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Reference':
      f.setItemControlBehavior('bp_ref2', result[0].Value, true);
      f.setReferenceKeyFilter('ma_nv2');
      f.setItemValue('ma_nv2', '');
      break;
    default:
      break;
  }
}
/* </flatten> */
